import{_ as a,o as i,c as e,a2 as s}from"./chunks/framework.BWuWLRhz.js";const n="/assets/cases/yifangyiwan/app-architecture.png",r="/assets/cases/yifangyiwan/pdf/product-detail-structure-06.png",l="/assets/cases/yifangyiwan/pdf/user-path-22.png",o="/assets/cases/yifangyiwan/pdf/mobile-home-16.png",p="/assets/cases/yifangyiwan/pdf/mobile-find-47.png",d="/assets/cases/yifangyiwan/pdf/mobile-detail-01.png",h="/assets/cases/yifangyiwan/pdf/mobile-subscribe-15.png",g="/assets/cases/yifangyiwan/pdf/mobile-recognition-monitor-50.png",y=JSON.parse('{"title":"一房一万新房小程序","description":"","frontmatter":{},"headers":[],"relativePath":"projects/lansi/yifangyiwan-new-home.md","filePath":"projects/lansi/yifangyiwan-new-home.md"}'),c={name:"projects/lansi/yifangyiwan-new-home.md"};function f(u,t,b,m,_,x){return i(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="一房一万新房小程序" tabindex="-1">一房一万新房小程序 <a class="header-anchor" href="#一房一万新房小程序" aria-label="Permalink to &quot;一房一万新房小程序&quot;">​</a></h1><blockquote><p>我从进入澜思开始主导的长期核心项目，持续 6 年负责新房业务产品化和小程序核心迭代。这个项目从早期“房导航”推翻重做到 2020 年 5.0 版本上线，再伴随上海新房市场从高热到下行、政策从收紧到逐步放宽持续迭代。到 2025 年我离开时，小程序累计用户达到 <span class="text-highlight-blue">80 万+</span>。</p></blockquote><div class="project-snapshot"><div><strong>6 年</strong><span>持续主导新房小程序产品业务、流程与核心版本迭代</span></div><div><strong>80 万+</strong><span>截至 2025 年的小程序累计用户规模</span></div><div><strong>5.0</strong><span>2020 年重构上线的关键版本，建立新房决策主路径</span></div><div><strong>独家数据</strong><span>以新房成交数据、楼盘状态、用户行为和内容数据形成差异化</span></div></div><h2 id="项目定位" tabindex="-1">项目定位 <a class="header-anchor" href="#项目定位" aria-label="Permalink to &quot;项目定位&quot;">​</a></h2><p>一房一万新房小程序，原名“房导航”，是面向上海购房者的新房决策产品。它要解决的核心问题，是让用户在政策复杂、信息分散、节点频繁变化的新房市场里，判断 <span class="text-highlight">哪些楼盘适合自己</span>、<span class="text-highlight">什么时候应该关注</span>、<span class="text-highlight">认购和摇号进展如何</span>，以及 <span class="text-highlight-warm">价格、成交、户型、日照、周边和资格条件</span> 是否匹配自己的购房决策。</p><p>公开产品入口可以参考 <a href="https://www.realtynavi.com/" target="_blank" rel="noreferrer">一房一万官网</a>。“一房一万，大数据帮您选房”是这条产品线对外最直接的表达。官网与小程序属于同一套新房找房和数据决策能力，<span class="text-highlight-blue">官网更偏地图化展示和公开访问</span>，小程序更偏移动端用户路径、订阅提醒、授权手机号、进群、报名咨询和后续转化闭环。</p><p>新房市场有大量公开信息，但真正形成产品壁垒的是数据的结构化和时效性。澜思掌握的 <span class="text-highlight-blue">新房成交数据</span> 是关键差异：它能让用户看到真实成交、网签热度、楼盘批次状态和市场走势，也让产品从“信息展示”升级为“数据辅助决策”。</p><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><p>2019 年前后，上海新房市场的线上信息已经很多，但购房者仍然需要在公众号、楼盘海报、销售口径、政府公示、社群消息和多个工具之间来回切换。一个用户想买新房，通常需要同时关心：</p><ul><li>楼盘是否即将入市、是否取证、是否认筹、是否摇号、是否在售。</li><li>楼盘价格、总价段、面积、户型、一房一价、日照、周边配套。</li><li>自己的购房资格、积分预估、认购要求和摇号结果。</li><li>市场成交热度、网签数据、同区域竞品楼盘和未来供应。</li><li>从公众号内容、社群信息、小程序浏览到报名咨询的完整路径。</li></ul><p>这意味着产品不能只做楼盘列表。它需要把新房业务流程、数据口径、页面结构、内容运营、用户行为和销售转化串成一条可追踪的链路。后来 2021 年之后房地产行业进入下行周期，市场热度、用户需求和政策环境都发生变化，这个产品也不断围绕新政策、新需求和新房市场阶段做调整。</p><h2 id="项目目标" tabindex="-1">项目目标 <a class="header-anchor" href="#项目目标" aria-label="Permalink to &quot;项目目标&quot;">​</a></h2><ol><li>建立面向购房者的 <span class="text-highlight">新房数据决策工具</span>，让用户可以用价格、区域、户型、认筹、摇号、成交和周边数据筛选楼盘。</li><li>重构从公众号内容、服务号、小程序、社群到报名咨询的用户路径，把流量触达、意向沉淀和后续服务连接起来。</li><li>建立页面埋点和用户行为分析体系，让首页、找房、楼盘详情、订阅、授权手机号、进群、报名等关键节点可以被追踪和复盘。</li><li>将公开楼盘信息、澜思独家成交数据、内容运营数据和广告投放数据整合进同一个产品体系。</li><li>支撑长期业务迭代：从 2019 年重做，到 2020 年 5.0 上线，再到后续围绕上海楼市政策和市场周期持续维护。</li></ol><h2 id="我的角色" tabindex="-1">我的角色 <a class="header-anchor" href="#我的角色" aria-label="Permalink to &quot;我的角色&quot;">​</a></h2><p>我在这个项目中承担的是 <span class="text-highlight-blue">核心产品负责人 / 数据产品角色</span>。具体工作既包括产品原型、页面结构和业务流程，也包括数据口径、埋点方案、用户路径、运营协同和长期版本迭代。</p><table tabindex="0"><thead><tr><th>模块</th><th>我承担的工作</th></tr></thead><tbody><tr><td>新房业务流程</td><td>梳理购房者从内容触达、楼盘浏览、订阅提醒、授权手机号、进群、报名到后续服务的路径</td></tr><tr><td>产品架构与原型</td><td>主导小程序改版，设计首页、找房、楼盘详情、一房一价、认筹监测、摇号结果、地图找房等核心模块</td></tr><tr><td>数据口径</td><td>梳理楼盘状态、批次、成交、网签、认筹、摇号、报名、用户行为等字段和页面展示逻辑</td></tr><tr><td>埋点与路径分析</td><td>设计埋点方案，跟进埋点问题复盘，让关键页面、停留时长、搜索、浏览、报名路径可分析</td></tr><tr><td>内容与增长协同</td><td>参与公众号数据分析、广告投放链路梳理，把公众号内容、私域社群和小程序转化接起来</td></tr><tr><td>长期迭代维护</td><td>根据上海新房政策变化、市场热度变化和业务反馈持续调整功能、页面和数据表达</td></tr></tbody></table><p>楼市基本面、数说楼市等内容由运营主导，我更多是参与协作：把内容、数据结构和小程序触点衔接起来，让运营内容可以服务用户决策和转化路径。</p><h2 id="版本推进" tabindex="-1">版本推进 <a class="header-anchor" href="#版本推进" aria-label="Permalink to &quot;版本推进&quot;">​</a></h2><h3 id="_2019-推翻重做-打通用户体系" tabindex="-1">2019：推翻重做，打通用户体系 <a class="header-anchor" href="#_2019-推翻重做-打通用户体系" aria-label="Permalink to &quot;2019：推翻重做，打通用户体系&quot;">​</a></h3><p>2019 年 5-7 月，我开始整理既有资料和业务流程；8 月明确房导航 C 端、B 端和后台系统的功能边界；9-10 月开始打通公众号、服务号、小程序和社群之间的流转逻辑。这个阶段的重点是把原本分散的资源统一到一套用户体系里：用户通过不同入口进入产品后，需要能被识别、沉淀和服务。</p><p>其中很关键的一步是建立 <span class="text-highlight">用户授权体系</span>：把不同途径登录的用户统一为一个用户标识，为后续行为分析、报名入库和销售跟进打基础。</p><h3 id="_2020-5-0-上线-建立新房决策主路径" tabindex="-1">2020：5.0 上线，建立新房决策主路径 <a class="header-anchor" href="#_2020-5-0-上线-建立新房决策主路径" aria-label="Permalink to &quot;2020：5.0 上线，建立新房决策主路径&quot;">​</a></h3><p>2020 年，新房市场热度较高，产品进入关键版本重构。5.0 版本围绕新房模块重新梳理：楼盘信息、一房一价、电子沙盘、认购监测、摇号结果、报名咨询、地图找房和购房资料等能力逐步成型。</p><p>这一版的核心，是把“看楼盘”推进到“做决策”：用户看到楼盘详情后，可以继续结合价格、认购节点、摇号进展、户型面积、周边配套和市场热度判断是否值得关注。</p><h3 id="_2021-2025-跟随政策和市场长期迭代" tabindex="-1">2021-2025：跟随政策和市场长期迭代 <a class="header-anchor" href="#_2021-2025-跟随政策和市场长期迭代" aria-label="Permalink to &quot;2021-2025：跟随政策和市场长期迭代&quot;">​</a></h3><p>2021 年之后，房地产市场逐步下行，上海新房政策也经历了从收紧到逐步放宽的过程。产品继续围绕购房资格、认购规则、市场热度、用户路径和内容触达做迭代。这个项目让我完整经历了一个城市新房市场从高峰到下行的周期，也让我深刻理解：数据产品不能只跟着需求做页面，必须跟着行业周期、政策变化和用户决策心理一起调整。</p><h2 id="产品架构与核心页面" tabindex="-1">产品架构与核心页面 <a class="header-anchor" href="#产品架构与核心页面" aria-label="Permalink to &quot;产品架构与核心页面&quot;">​</a></h2><div class="case-image-grid"><figure><img src="'+n+'" alt="一房一万新房小程序产品架构"><figcaption><strong>小程序整体产品架构</strong><span>围绕首页、找房、问答、我的等一级结构展开，把楼盘、价格、认购、摇号、资格查询和用户服务统一到同一个入口。</span></figcaption></figure><figure><img src="'+r+'" alt="楼盘详情页优化框架"><figcaption><strong>楼盘详情页优化框架</strong><span>详情页承载批次状态、重点功能、认购前后动态和报名入口，是用户判断楼盘价值的核心决策页面。</span></figcaption></figure><figure><img src="'+l+'" alt="用户路径与行为分析设计"><figcaption><strong>用户路径与行为分析设计</strong><span>记录搜索、区域板块、浏览项目、户型面积、页面名称、停留时长和报名路径，让产品迭代有数据依据。</span></figcaption></figure></div><div class="case-mobile-grid"><figure><img src="'+o+'" alt="一房一万小程序首页"><figcaption><strong>首页</strong><span>把即将上市、取证、认筹、摇号、网签、资格查询和优质推荐集中呈现，形成用户进入新房市场的第一屏。</span></figcaption></figure><figure><img src="'+p+'" alt="一房一万小程序找房页"><figcaption><strong>找房页</strong><span>支持按区域、价格、户型、面积和楼盘状态筛选，让用户快速找到适合自己的新房项目。</span></figcaption></figure><figure><img src="'+d+'" alt="一房一万小程序楼盘详情页"><figcaption><strong>楼盘详情页</strong><span>承载楼盘状态、价格、地址、户型、楼盘动态、一房一价、购房资料和电话咨询等关键转化入口。</span></figcaption></figure><figure><img src="'+h+'" alt="一房一万小程序楼盘详情长页"><figcaption><strong>详情长页</strong><span>把认筹、楼盘信息、户型图、电子沙盘、历史摇号、用户评论和相关推荐组织成完整决策页面。</span></figcaption></figure><figure><img src="'+g+'" alt="一房一万认筹监测"><figcaption><strong>认筹监测</strong><span>用数据展示总房源数、认筹时间、认筹率、认筹走势和认筹分布，帮助用户判断项目热度。</span></figcaption></figure></div><h2 id="数据体系建设" tabindex="-1">数据体系建设 <a class="header-anchor" href="#数据体系建设" aria-label="Permalink to &quot;数据体系建设&quot;">​</a></h2><p>这个项目的核心难点，是把“公开信息”转成“可决策数据”。我把它拆成四层：</p><h3 id="_1-楼盘与状态数据" tabindex="-1">1. 楼盘与状态数据 <a class="header-anchor" href="#_1-楼盘与状态数据" aria-label="Permalink to &quot;1. 楼盘与状态数据&quot;">​</a></h3><p>新房楼盘具有很强的阶段性。一个项目会经历待入市、取证、认筹、摇号、开盘、在售、售罄等阶段，每个阶段对应不同字段、不同页面重点和不同用户行为。产品需要及时展示状态变化，也要让用户能按状态筛选、订阅和接收提醒。</p><p>例如：用户关注某个楼盘后，需要在售楼处开放、取证、认筹、摇号、摇号结果等节点收到消息；找房页也需要按即将上市、最新取证、认筹、摇号等状态组织列表。</p><h3 id="_2-成交与热度数据" tabindex="-1">2. 成交与热度数据 <a class="header-anchor" href="#_2-成交与热度数据" aria-label="Permalink to &quot;2. 成交与热度数据&quot;">​</a></h3><p>新房基础信息很多平台都有，但澜思的优势在于 <span class="text-highlight-blue">新房成交数据</span>。成交、网签、批次、认筹和摇号数据可以帮助用户判断楼盘热度，也能帮助产品构建“哪些项目值得关注”的推荐逻辑。</p><p>这类数据让一房一万的表达从“楼盘介绍”升级为“市场判断”：用户除了价格和图片，还能看到项目在真实市场里的表现。</p><h3 id="_3-用户行为与转化数据" tabindex="-1">3. 用户行为与转化数据 <a class="header-anchor" href="#_3-用户行为与转化数据" aria-label="Permalink to &quot;3. 用户行为与转化数据&quot;">​</a></h3><p>我参与设计了埋点方案和问题复盘机制，重点关注用户从内容到小程序再到报名服务的路径。资料中明确记录了页面名称、页面停留时间、搜索关键词、区域板块、浏览项目、户型面积、认购监测、周边配套、报名路径等字段。</p><p>这使产品能够回答更具体的问题：用户从哪里进来、看了哪些楼盘、在哪些页面停留、是否授权手机号、是否进群、是否报名、哪些入口更有效。</p><h3 id="_4-内容与渠道数据" tabindex="-1">4. 内容与渠道数据 <a class="header-anchor" href="#_4-内容与渠道数据" aria-label="Permalink to &quot;4. 内容与渠道数据&quot;">​</a></h3><p>一房一万的用户增长同时发生在公众号、社群、广告投放和小程序里。公众号内容会影响用户进入小程序的路径，广告投放会影响获客质量，社群又承接用户后续咨询和转化。</p><p>我参与公众号数据分析和广告投放链路梳理，把内容、渠道和小程序行为放在同一条增长链路里看。运营主导内容生产，我负责把内容触点、产品入口和数据复盘连接起来。</p><h2 id="阶段成果" tabindex="-1">阶段成果 <a class="header-anchor" href="#阶段成果" aria-label="Permalink to &quot;阶段成果&quot;">​</a></h2><table tabindex="0"><thead><tr><th>成果</th><th style="text-align:right;">数据 / 表现</th><th>说明</th></tr></thead><tbody><tr><td>累计用户规模</td><td style="text-align:right;"><span class="text-highlight-blue">80 万+</span></td><td>截至 2025 年离开时的小程序累计用户</td></tr><tr><td>早期用户记录</td><td style="text-align:right;">19.3 万+ 用户人数记录</td><td>2019.08-2020.11 阶段资料中可追溯数据</td></tr><tr><td>早期访问人次</td><td style="text-align:right;">97.9 万+ 用户人次</td><td>2019.08-2020.11 阶段小程序访问记录</td></tr><tr><td>授权手机号用户</td><td style="text-align:right;">7.46 万+</td><td>2019.08-2020.11 阶段授权手机号用户记录</td></tr><tr><td>新房报名</td><td style="text-align:right;">3,510 人 / 4,918 人次</td><td>2019.01-2020.11 阶段报名数据</td></tr><tr><td>关键版本</td><td style="text-align:right;">2020 年 5.0</td><td>完成新房决策主路径重构并上线</td></tr></tbody></table><p>这些数据说明，这个项目长期承载了 C 端用户增长、楼盘数据服务、私域转化和销售线索沉淀，是澜思新房业务非常核心的产品入口。</p><h2 id="项目价值" tabindex="-1">项目价值 <a class="header-anchor" href="#项目价值" aria-label="Permalink to &quot;项目价值&quot;">​</a></h2><p>对用户来说，一房一万新房小程序降低了新房决策成本。用户可以围绕楼盘状态、总价段、户型面积、认筹摇号、一房一价、日照、周边和成交热度快速比较，不需要在多个渠道里拼信息。</p><p>对业务来说，它把公众号、社群、小程序、广告和销售服务接成一条链路。用户行为可以沉淀，报名路径可以追踪，楼盘热度可以复盘，内容选题和转化入口也能通过数据持续优化。</p><p>对我个人来说，这个项目是我数据产品能力的基础训练场。我在这里完整经历了从业务理解、产品架构、原型设计、数据口径、埋点方案、版本上线、运营协同到长期迭代的全过程，也第一次非常深刻地感受到：<span class="text-highlight-warm">数据资产的价值，最终体现在用户是否理解、业务是否使用、团队是否能持续复盘。</span></p><p>这段经历也影响了我后来的产品判断。无论是金融数据看板、客户标签、埋点治理，还是个人做紫微斗数数据化解读系统，我都会优先思考：数据从哪里来，准确性如何建立，用户为什么相信它，它最后如何转化成一个可被理解、可被验证、可持续迭代的产品。</p>',51)])])}const k=a(c,[["render",f]]);export{y as __pageData,k as default};
